/* ── DATE HELPER ──────────────────────────────────────────────────────────── */
/** Returns today's date as D/M/YYYY (e.g. "10/3/2026") */
function getToday() {
  const d = new Date();
  return d.getDate() + '/' + (d.getMonth() + 1) + '/' + d.getFullYear();
}

